Write a program to test if a given sequence Seq is a topological order of a given graph Graph.

Format of functions:
```c
bool IsTopSeq(LGraph Graph, Vertex Seq[]);
```

where LGraph is defined as the following:
```c
typedef struct AdjVNode *PtrToAdjVNode;
struct AdjVNode {
    Vertex AdjV;
    PtrToAdjVNode Next;
};
typedef struct Vnode {
    PtrToAdjVNode FirstEdge;
} AdjList[MaxVertexNum];
typedef struct GNode *PtrToGNode;
struct GNode {
    int Nv;
    int Ne;
    AdjList G;
};
typedef PtrToGNode LGraph;
```

The function IsTopSeq must return true if Seq does correspond to a topological order; otherwise return false.

Note: Although the vertices are numbered from 1 to MaxVertexNum, they are indexed from 0 in the LGraph structure.

answer.codeSnippet:
bool IsTopSeq(LGraph Graph, Vertex Seq[]) {
    int degree[MaxVertexNum];
    int i;
    PtrToAdjVNode p;
    for (i = 0; i < Graph->Nv; i++)
        degree[i] = 0;
    for (i = 0; i < Graph->Nv; i++)
        for (p = Graph->G[i].FirstEdge; p; p = p->Next)
            degree[p->AdjV]++;
    for (i = 0; i < Graph->Nv; i++) {
        if (degree[Seq[i] - 1] != 0)
            return false;
        for (p = Graph->G[Seq[i] - 1].FirstEdge; p; p = p->Next)
            degree[p->AdjV]--;
    }
    return true;
}

